-- Dev/test password for every seeded user: password
-- BCrypt hash generated by the local Spring PasswordEncoder.
WITH seed_users(id_user, firstname, lastname, username, email, bio) AS (
    VALUES
        ('10000000-0000-4000-8000-000000000001'::uuid, 'Alice', 'Morel', 'alice_author', 'alice.author@plumora.test', 'Autrice de fantasy atmospherique.'),
        ('10000000-0000-4000-8000-000000000002'::uuid, 'Bruno', 'Kassel', 'bruno_author', 'bruno.author@plumora.test', 'Auteur de thrillers courts.'),
        ('10000000-0000-4000-8000-000000000003'::uuid, 'Clara', 'Vidal', 'clara_reader', 'clara.reader@plumora.test', 'Lectrice reguliere.'),
        ('10000000-0000-4000-8000-000000000004'::uuid, 'Noah', 'Sorel', 'noah_beta', 'noah.beta@plumora.test', 'Beta-lecteur sensible au rythme.'),
        ('10000000-0000-4000-8000-000000000005'::uuid, 'Lina', 'Park', 'lina_beta', 'lina.beta@plumora.test', 'Beta-lectrice specialisee personnages.'),
        ('10000000-0000-4000-8000-000000000006'::uuid, 'Admin', 'Plumora', 'admin_plumora', 'admin@plumora.test', 'Compte admin local.')
)
INSERT INTO users (id_user, firstname, lastname, username, email, password_hash, avatar_url, bio, is_active, created_at, updated_at)
SELECT
    id_user,
    firstname,
    lastname,
    username,
    email,
    '$2a$10$hitz6ikg/grYTEyhlMlzXe2tPujxA2vHpFKU8v14gcpEWVPZrtlkm',
    'https://placehold.co/256x256?text=' || upper(left(firstname, 1)) || upper(left(lastname, 1)),
    bio,
    TRUE,
    now() - interval '20 days',
    now()
FROM seed_users
ON CONFLICT (email) DO UPDATE SET
    firstname = EXCLUDED.firstname,
    lastname = EXCLUDED.lastname,
    username = EXCLUDED.username,
    password_hash = EXCLUDED.password_hash,
    avatar_url = EXCLUDED.avatar_url,
    bio = EXCLUDED.bio,
    is_active = TRUE,
    updated_at = now();

WITH assignments(email, role_name) AS (
    VALUES
        ('alice.author@plumora.test', 'AUTHOR'),
        ('alice.author@plumora.test', 'READER'),
        ('bruno.author@plumora.test', 'AUTHOR'),
        ('clara.reader@plumora.test', 'READER'),
        ('noah.beta@plumora.test', 'READER'),
        ('noah.beta@plumora.test', 'BETA_READER'),
        ('lina.beta@plumora.test', 'READER'),
        ('lina.beta@plumora.test', 'BETA_READER'),
        ('admin@plumora.test', 'ADMIN')
)
INSERT INTO user_roles (id_user, id_role, assigned_at)
SELECT u.id_user, r.id_role, now() - interval '20 days'
FROM assignments a
JOIN users u ON u.email = a.email
JOIN roles r ON r.name = a.role_name
ON CONFLICT (id_user, id_role) DO NOTHING;

