    updated_at = EXCLUDED.updated_at;

UPDATE books b
SET average_rating = COALESCE(r.avg_rating, 0.00)
FROM (
    SELECT book_id, round(avg(rating)::numeric, 2) AS avg_rating
    FROM reviews
    GROUP BY book_id
) r
WHERE b.id_book = r.book_id;

